spec.root_selector:
(
  $dados := $map(
    $filter($, function($v) {
      $contains($v.path, "/properties/latestValue") and
      $contains($v.path, "DispX")
    }),
    function($v) {
      {
        "time": $substringBefore($v.time, "T"),
        "valor": $number($v.value.valor),
        "disp_num": $number(
          $substringBefore($substringAfter($v.path, "DispX"), "/")
        ),
        "path": $v.path
      }
    }
  );

  $datas := $sort($distinct($dados.time));
  $data_antiga  := $datas[0];
  $data_recente := $datas[-1];

  $append(
    $map(
      $distinct($dados.disp_num),
      function($d) {
        (
          $reg_recente := $filter($dados, function($r) { $r.time = $data_recente and $r.disp_num = $d })[0];
          $reg_antigo  := $filter($dados, function($r) { $r.time = $data_antiga  and $r.disp_num = $d })[0];
      {
          "disp_num":       $d,
          "time_recente":   $reg_recente.time,
          "valor_recente":  $reg_recente.valor,
          "time_antigo":    $reg_antigo.time,
          "valor_antigo":   $reg_antigo.valor,
          "valor": $number($reg_recente.valor) - $number($reg_antigo.valor),
          "path": "Displacement (mm)"
        }
        )
      }
  ),
    [
      { "valor": -15, "path": "Alert 1",         "disp_num": 0  },
      { "valor": -15, "path": "Alert 1",         "disp_num": 40 },
      { "valor":  15, "path": "Alert 2",        "disp_num": 0  },
